import{_ as a,c as e,a as i,o as n}from"./app-CEcM0piI.js";const l={};function t(d,s){return n(),e("div",null,s[0]||(s[0]=[i(`<h3 id="传统网页布局的三种方式" tabindex="-1"><a class="header-anchor" href="#传统网页布局的三种方式"><span>传统网页布局的三种方式</span></a></h3><p>网页布局的本质--用CSS来摆放盒子。把盒子摆放到相应位置CSS提供了三种传统布局方式（简单说，就是盒子如何进行排列顺序）：</p><ol><li>普通流（标准流）</li><li>浮动</li><li>定位</li></ol><h4 id="标准流-普通流-文档流" tabindex="-1"><a class="header-anchor" href="#标准流-普通流-文档流"><span>标准流（普通流/文档流）</span></a></h4><p>所谓的标准流：就是标签按照规定好默认方式排列.</p><ol><li><p>块级元素会独占一行，从上向下顺序排列。 常用元素：div、hr、p、h1~h6、ul、ol、dl、form、table</p></li><li><p>行内元素会按照顺序，从左到右顺序排列，碰到父元素边缘则自动换行。 常用元素：span、a、i、em等</p></li></ol><p>以上都是标准流布局，我们前面学习的就是标准流，标准流是最基本的布局方式。这三种布局方式都是用来摆放盒子的，盒子摆放到合适位置，布局自然就完成了。</p><p>标准流的盒子只会按照默认的方式排列,如果需要盒子不换行将其转换成行内块元素其盒子与盒子之间会有缝隙</p><p>浮动可以跟随页面的滚动而滚动,且可以实现盒子之间的对齐</p><p><mark>网页布局第一准则：多个块级元素纵向排列找标准流，多个块级元素横向排列找浮动。</mark></p><h1 id="浮动" tabindex="-1"><a class="header-anchor" href="#浮动"><span>浮动</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>选择器{ float:属性值;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th>属性值</th><th>描述</th></tr></thead><tbody><tr><td>none</td><td>元素不浮动（默认值）</td></tr><tr><td>left</td><td>元素向左浮动</td></tr><tr><td>right</td><td>元素向右浮动</td></tr></tbody></table><h3 id="浮动特性" tabindex="-1"><a class="header-anchor" href="#浮动特性"><span>浮动特性</span></a></h3><p>加了浮动之后的元素，会具有很多特性</p><ol><li><p>浮动元素会脱离标准流（脱标),浮动的盒子不再保留原先的位置 浮动相当于多加了一个z轴(图层),浮动的盒子在图层的顶端 后面添加的盒子填上浮动盒子原先的位置</p></li><li><p>浮动的元素会一行内显示并且元素顶部对齐 浮动都是上边缘对齐 浮动的元素是互相贴靠在一起的（不会有缝隙），如果父级宽度装不下这些浮动的盒子，多出的盒子会另起一行对齐。</p></li><li><p>浮动的元素会具有行内块元素的特性 任何元素都可以浮动。不管原先是什么模式的元素，添加浮动之后具有行内块元素相似的特性。</p></li></ol><p><strong>浮动元素经常和标准流的父元素搭配使用</strong> 为了约束浮动元素位置,我们网页布局一般采取的策略是：先用标准流的父元素排列上下位置，之后内部子元素采取浮动排列左右位置.符合网页布局第一准侧</p><p>标准流独占一行,若后面的盒子浮动了它只会压着后面的标准流,而不会压着前面的标准流</p><p>如果想要让父元素的高度根据它里面的浮动元素的数量来调节高度不可以将父元素的高度设为0,因为浮动不占有位置,当设为0时只出现了浮动的子盒子,父盒子变为0</p><h3 id="清除浮动" tabindex="-1"><a class="header-anchor" href="#清除浮动"><span>清除浮动</span></a></h3><p>清除浮动的本质是清除浮动元素造成的影响如果父盒子本身有高度，则不需要清除浮动 清除浮动之后，父级就会根据浮动的子盒子自动检测高度。 父级有了高度，就不会影响下面的标准流了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>选择器{clear:属性值;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th>属性值</th><th>描述</th></tr></thead><tbody><tr><td>left</td><td>不允许左侧有浮动元素 (清除左侧浮动的影响)</td></tr><tr><td>right</td><td>不允许右侧有浮动元素 (清除右侧浮动的影响)</td></tr><tr><td>both</td><td>同时清除左右两侧浮动的影响</td></tr></tbody></table><p>我们实际工作中，几乎只用clear:both; 清除浮动的策略是：闭合浮动</p><h4 id="额外标签法" tabindex="-1"><a class="header-anchor" href="#额外标签法"><span>额外标签法</span></a></h4><p>额外标签法也称为隔墙法，是W3C推荐的做法。额外标签法会在浮动元素末尾添加一个空的标签。例如&lt;div style=”clear:both”&gt;&lt;/div&gt;，或者其他标签（如<br>等）。</p><p>在设置过浮动的盒子后面添加一个额外的标签,并在额外的标签中添加清除浮动,这样就将浮动的盒子与后面的盒子隔开了</p><ul><li>优点：通俗易懂，书写方便</li><li>缺点：添加许多无意义的标签，结构化较差</li></ul><blockquote><p>[!warning] 注意 要求这个新的空标签必须是块级元素</p></blockquote><h4 id="父级添加overflow" tabindex="-1"><a class="header-anchor" href="#父级添加overflow"><span>父级添加overflow</span></a></h4><p>可以给父级添加overflow属性，将其属性值设置为hidden、auto或scroll。都可以</p><ul><li>优点：代码简洁</li><li>缺点：无法显示溢出的部分</li></ul><h4 id="after伪元素法" tabindex="-1"><a class="header-anchor" href="#after伪元素法"><span>:after伪元素法</span></a></h4><p>:after方式是额外标签法的升级版,给父元素添加</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>.clearfix:after {</span></span>
<span class="line"><span>    content: &quot;&quot;;</span></span>
<span class="line"><span>    display: block;</span></span>
<span class="line"><span>    height: 0;</span></span>
<span class="line"><span>    clear: both;</span></span>
<span class="line"><span>    visibility: hidden;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>.clearfix {</span></span>
<span class="line"><span>    /*IE6、7专有*/</span></span>
<span class="line"><span>    *zoom: 1;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>优点：没有增加标签，结构更简单</li><li>缺点：照顾低版本浏览器</li></ul><h4 id="双伪元素清除浮动" tabindex="-1"><a class="header-anchor" href="#双伪元素清除浮动"><span>双伪元素清除浮动</span></a></h4><p>给父元素添加</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>.clearfix:before,.clearfix:after {</span></span>
<span class="line"><span>    content: &quot;&quot;;</span></span>
<span class="line"><span>    display: table;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>.clearfix:after {</span></span>
<span class="line"><span>    clear: both;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>.clearfix {</span></span>
<span class="line"><span>    *zoom:1;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>优点：代码更简洁</li><li>缺点：照顾低版本浏览器</li></ul>`,40)]))}const r=a(l,[["render",t]]),c=JSON.parse('{"path":"/front/css/5/","title":"5 浮动","lang":"zh-CN","frontmatter":{"title":"5 浮动","createTime":"2025/06/18 21:05:54","permalink":"/front/css/5/"},"readingTime":{"minutes":4.36,"words":1309},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/CSS/5 浮动.md","headers":[]}');export{r as comp,c as data};
